package com.museumheist.game.logic;import org.junit.Test;import static org.junit.Assert.*;public class VisionTest{@Test public void ahead(){assertTrue(Vision.canSee(0,0,1,0,100,(float)Math.PI/2,50,0));}@Test public void behind(){assertFalse(Vision.canSee(0,0,1,0,100,(float)Math.PI/2,-10,0));}@Test public void range(){assertFalse(Vision.canSee(0,0,1,0,10,(float)Math.PI,11,0));}@Test public void origin(){assertFalse(Vision.canSee(0,0,1,0,100,(float)Math.PI,0,0));}@Test public void boundary(){float a=(float)Math.PI/2,t=a/2;assertTrue(Vision.canSee(0,0,1,0,100,a,(float)Math.cos(t)*50,(float)Math.sin(t)*50));}}